    const cap = tcount * 36; // Mon-Sat 6 slots
    return {courseId, sessions:sess, teachers:tcount, teacher_capacity:cap, overloaded: tcount>0 ? sess>cap : true};
  }).sort((a,b)=> (b.sessions-b.teacher_capacity) - (a.sessions-a.teacher_capacity));

  console.log('MAX_STUDENT_WEEKLY_HOURS_TOP10', JSON.stringify(maxStudent));
  console.log('GROUPS_OVER_36_TOP', JSON.stringify(over36Groups));
  console.log('TEACHER_BOTTLENECKS_TOP20', JSON.stringify(teacherBottlenecks.filter(x=>x.overloaded).slice(0,20)));
  console.log('TOTAL_OVERLOADED_COURSES', teacherBottlenecks.filter(x=>x.overloaded).length);
})();
