 62	  private async fetchAllRows(table: string, columns: string, orderBy?: string): Promise<any[]> {
 63	    const rows: any[] = [];
 64	    let from = 0;
 65	
 66	    while (true) {
 67	      let query: any = supabase.from(table).select(columns);
 68	      if (orderBy) query = query.order(orderBy, { ascending: true });
 69	      const { data, error } = await query.range(from, from + this.pageSize - 1);
 70	      if (error) throw error;
 71	
 72	      const batch = data || [];
 73	      rows.push(...batch);
 74	      if (batch.length < this.pageSize) break;
 75	      from += this.pageSize;
 76	    }
 77	
 78	    return rows;
 79	  }
