require('dotenv').config();
const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);

const pageSize = 1000;
async function fetchAll(table, columns='*', orderBy){
  let from=0; const out=[];
  while(true){
    let q = supabase.from(table).select(columns);
    if(orderBy) q=q.order(orderBy,{ascending:true});
    const {data,error} = await q.range(from, from+pageSize-1);
    if(error) throw error;
    const batch=data||[]; out.push(...batch);
    if(batch.length<pageSize) break;
    from += pageSize;
  }
  return out;
}

const specializationPrefixes = ['FSE','AIM','CLD','CYB','DSE'];
const minorPrefixes = ['MWD','MDL','MDO','MBC','MBA'];
const timeSlots = [
  '09:00 AM - 09:50 AM','10:00 AM - 10:50 AM','11:00 AM - 11:50 AM','12:00 PM - 12:50 PM',
  '01:30 PM - 02:20 PM','02:30 PM - 03:20 PM','03:30 PM - 04:20 PM','04:30 PM - 05:20 PM'
];
const days = ['Mon','Tue','Wed','Thu','Fri','Sat'];
const allTimes = days.flatMap(d=>timeSlots.map(s=>`${d} ${s}`));

function parseSemester(v){const m=String(v||'').trim().match(/(\d+)/); if(!m) return 1; const n=Number(m[1]); return Number.isNaN(n)?1:Math.max(1,Math.min(8,n));}
function getBatchToken(studentId){const m=String(studentId).match(/^(\d{3})/); return m?m[1]:'GEN';}
function norm(v,f){return String(v||f).toUpperCase().replace(/\s+/g,'_').replace(/\//g,'_').replace(/[^A-Z0-9_]/g,'');}
function bucket(courseId){const p=String(courseId||'').slice(0,3).toUpperCase(); if(specializationPrefixes.includes(p)) return 'Specialization'; if(minorPrefixes.includes(p)) return 'Minor'; return 'Core';}
function groupingId(b,sem,student,sid){const bt=getBatchToken(sid); const sp=norm(student?.specialization_id,'GENERAL'); const mn=norm(student?.minor_id,'GENERAL'); const pw=norm(student?.pathway_id,'P0'); if(b==='Specialization') return `SPEC-${bt}-SEM${sem}-${sp}`; if(b==='Minor') return `MINOR-${bt}-SEM${sem}-${mn}`; return `CORE-${bt}-SEM${sem}-MINOR-${mn}-PATH-${pw}`;}

(async()=>{
  const [rooms, courses, enrollments, students, master, teacherSubjects, faculty] = await Promise.all([
    fetchAll('infrastructure','*','room_id'),
    fetchAll('courses','*','course_id'),
    fetchAll('student_enrollments','*','student_id'),
    fetchAll('students','student_id, specialization_id, minor_id, pathway_id, is_byod','student_id'),
    fetchAll('master_timetable','*','section_name'),
    fetchAll('teacher_subjects','*','teacher_id'),
    fetchAll('faculty','teacher_id,name,forbidden_slots','teacher_id')
  ]);

  const roomById = new Map(rooms.map(r=>[r.room_id,r]));
  const courseById = new Map(courses.map(c=>[c.course_id,c]));
  const studentById = new Map(students.map(s=>[s.student_id,s]));
  const facultyById = new Map(faculty.map(f=>[f.teacher_id,f]));
  const facultyNameToId = new Map(faculty.map(f=>[String(f.name||''), f.teacher_id]));

  const enrollmentGroups = new Map();
  const meta = new Map();
  for (const e of enrollments){
    const st = studentById.get(e.student_id);
    const sem = parseSemester(e.semester);
    const gid = groupingId(bucket(e.course_id), sem, st, e.student_id);
    const key = `${e.course_id}__SEM${sem}__${gid}`;
    if(!enrollmentGroups.has(key)){
      enrollmentGroups.set(key, []);
      meta.set(key, {courseId:e.course_id, sem, gid, requiresByod:false});
    }
    enrollmentGroups.get(key).push(e.student_id);
    if (st?.is_byod) meta.get(key).requiresByod = true;
  }

  const expected = [];
  for (const [key, studentsArr] of enrollmentGroups.entries()){
    const m = meta.get(key);
    const c = courseById.get(m.courseId);
    if(!c) continue;
    const sectionType = String(c.course_type||'').toLowerCase().includes('lab') ? 'Lab' : 'Lecture';
    const maxCap = sectionType==='Lab'?30:60;
    const chunks = [];
    for(let i=0;i<studentsArr.length;i+=maxCap) chunks.push(studentsArr.slice(i,i+maxCap));
    const sessions = Math.max(1, Number(c.credit_hours||1));
    const gcode = String(m.gid).replace(/[^A-Za-z0-9-]/g, '').slice(0,40);
    chunks.forEach((chunk,idx)=>{
      expected.push({
        section_name: `${m.courseId}-SEM${m.sem}-${gcode}-P${idx+1}`,
        courseId: m.courseId,
        type: sectionType,
        requiresByod: m.requiresByod,
        students: chunk,
        expected_sessions: sessions
      });
    });
  }

  const placedBySection = new Map();
  for(const a of master){
    const s = a.section_name;
    if(!placedBySection.has(s)) placedBySection.set(s, []);
    placedBySection.get(s).push(a);
  }

  const teacherLoad = new Map();
  for (const a of master){
    const id = facultyNameToId.get(String(a.instructor_name||'')) || String(a.instructor_name||'');
    teacherLoad.set(id,(teacherLoad.get(id)||0)+1);
  }

  const qualifiedByCourse = new Map();
  for (const m of teacherSubjects){
    if(!qualifiedByCourse.has(m.course_id)) qualifiedByCourse.set(m.course_id,[]);
    qualifiedByCourse.get(m.course_id).push(m.teacher_id);
  }

  const roomOcc = new Set(master.map(a=>`${a.room_id}|${a.time_slot}`));
  const studentOcc = new Set();
  const teacherOcc = new Set();
  for(const a of master){
    const sids = Array.isArray(a.student_ids)?a.student_ids:[];
    for(const sid of sids) studentOcc.add(`${sid}|${a.time_slot}`);
    const tid = facultyNameToId.get(String(a.instructor_name||'')) || String(a.instructor_name||'');
    teacherOcc.add(`${tid}|${a.time_slot}`);
  }

  function compatibleRooms(sec){
    return rooms.filter(r=>{
      const rt = String(r.room_type||'').toLowerCase();
      const isLabRoom = rt.includes('lab');
      if(sec.type==='Lab' && !isLabRoom) return false;
      if(sec.type==='Lecture' && isLabRoom) return false;
      if(sec.requiresByod && !r.is_byod_ready) return false;
      return Number(r.capacity_lecture||0) >= sec.students.length;
    });
  }

  const missing = [];
  for(const sec of expected){
    const placed = (placedBySection.get(sec.section_name)||[]).length;
    const miss = sec.expected_sessions - placed;
    if(miss>0) missing.push({...sec, placed, missing:miss, placedRows:placedBySection.get(sec.section_name)||[]});
  }

  const diagnosis = [];
  for(const sec of missing){
    let teacherId = null;
    if(sec.placedRows.length>0){
      teacherId = facultyNameToId.get(String(sec.placedRows[0].instructor_name||'')) || String(sec.placedRows[0].instructor_name||'');
    } else {
      const q = qualifiedByCourse.get(sec.courseId) || [];
      if(q.length){
        teacherId = [...q].sort((a,b)=>(teacherLoad.get(a)||0)-(teacherLoad.get(b)||0))[0];
      } else {
        // fallback least loaded faculty
        teacherId = faculty.length ? [...faculty].sort((a,b)=>(teacherLoad.get(a.teacher_id)||0)-(teacherLoad.get(b.teacher_id)||0))[0].teacher_id : 'UNKNOWN';
      }
    }

    const compRooms = compatibleRooms(sec);
    let feasibleByStudentTeacher = 0;
    let feasibleWithRoom = 0;
    for(const t of allTimes){
      let blocked = false;
      if(teacherOcc.has(`${teacherId}|${t}`)) blocked = true;
      if(!blocked){
        for(const sid of sec.students){ if(studentOcc.has(`${sid}|${t}`)){ blocked=true; break; } }
      }
      if(blocked) continue;
      feasibleByStudentTeacher++;
      let anyRoom=false;
      for(const r of compRooms){ if(!roomOcc.has(`${r.room_id}|${t}`)){ anyRoom=true; break; } }
      if(anyRoom) feasibleWithRoom++;
    }

    let reason = 'mixed_constraints';
    if(compRooms.length===0) reason = 'no_compatible_room';
    else if(feasibleByStudentTeacher===0) reason = 'student_teacher_time_conflict';
    else if(feasibleWithRoom===0) reason = 'room_full_at_feasible_times';

    diagnosis.push({section:sec.section_name, course:sec.courseId, missing:sec.missing, students:sec.students.length, teacher:teacherId, compatible_rooms:compRooms.length, free_times_student_teacher:feasibleByStudentTeacher, free_times_with_room:feasibleWithRoom, reason});
  }

  diagnosis.sort((a,b)=>b.missing-a.missing || a.reason.localeCompare(b.reason));
  const summary = diagnosis.reduce((acc,d)=>{acc[d.reason]=(acc[d.reason]||0)+d.missing; return acc;},{});
  console.log('UNPLACED_TOTAL', missing.reduce((s,x)=>s+x.missing,0));
  console.log('REASON_SUMMARY', JSON.stringify(summary));
  console.log('DETAILS', JSON.stringify(diagnosis, null, 2));
})();
