import { useState } from 'react';
import { Upload, FileSpreadsheet, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';

export default function DataImport() {
  const [file, setFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [result, setResult] = useState<any>(null);

  const handleUpload = async () => {
    if (!file) return;
    setUploading(true);
    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await fetch('http://localhost:4000/api/data/import', {
        method: 'POST',
        body: formData,
      });
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setResult({ success: false, message: 'Upload failed' });
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="view-container">
      <h2 style={{ marginBottom: '2rem' }}>Institutional Data Ingestion</h2>

      <div className="glass-card" style={{ maxWidth: '600px', textAlign: 'center', padding: '4rem 2rem' }}>
        <div 
          onClick={() => document.getElementById('file-input')?.click()}
          style={{ 
            border: '2px dashed var(--border)', 
            borderRadius: '12px', 
            padding: '3rem', 
            cursor: 'pointer',
            backgroundColor: 'rgba(255,255,255,0.02)',
            transition: 'all 0.2s'
          }}
        >
          <Upload size={48} style={{ color: 'var(--text-dim)', marginBottom: '1rem' }} />
          <h3>Click to Upload Excel/CSV</h3>
          <p style={{ color: 'var(--text-dim)', marginTop: '0.5rem' }}>Supporting Student Records, Room Lists, and Faculty Data</p>
          <input 
            id="file-input" 
            type="file" 
            hidden 
            onChange={(e) => setFile(e.target.files?.[0] || null)}
            accept=".xlsx, .xls, .csv"
          />
        </div>

        {file && (
          <div style={{ marginTop: '2rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '1rem' }}>
            <FileSpreadsheet style={{ color: 'var(--accent)' }} />
            <span style={{ fontWeight: 500 }}>{file.name}</span>
            <button 
              className="btn-primary" 
              onClick={handleUpload}
              disabled={uploading}
              style={{ padding: '0.5rem 1.5rem' }}
            >
              {uploading ? <Loader2 className="animate-spin" size={18} /> : 'Process Import'}
            </button>
          </div>
        )}

        {result && (
          <div style={{ 
            marginTop: '2rem', 
            padding: '1rem', 
            borderRadius: '8px', 
            backgroundColor: result.success ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)',
            color: result.success ? '#10b981' : '#ef4444',
            display: 'flex',
            alignItems: 'center',
            gap: '0.5rem',
            justifyContent: 'center'
          }}>
            {result.success ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
            {result.message}
          </div>
        )}
      </div>

      <div style={{ marginTop: '2rem', display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem' }}>
        <TemplateCard title="Student Template" />
        <TemplateCard title="Room Mapping" />
        <TemplateCard title="Instructor Availability" />
      </div>
    </div>
  );
}

function TemplateCard({ title }: { title: string }) {
  return (
    <div className="glass-card" style={{ textAlign: 'center' }}>
      <FileSpreadsheet size={24} style={{ color: 'var(--text-dim)', marginBottom: '0.5rem' }} />
      <div style={{ fontSize: '0.875rem', fontWeight: 500 }}>{title}</div>
      <button style={{ 
        marginTop: '1rem', 
        fontSize: '0.75rem', 
        background: 'none', 
        border: '1px solid var(--border)', 
        color: 'var(--accent)', 
        padding: '0.25rem 0.75rem', 
        borderRadius: '4px',
        cursor: 'pointer'
      }}>
        Download Template
      </button>
    </div>
  );
}

import { useState } from 'react';
