          </p>
          <label className="switch-container" style={{ display: 'flex', alignItems: 'center', gap: '1rem', cursor: 'pointer' }}>
            <input 
              type="checkbox" 
              checked={constraints.zeroBuffer} 
              onChange={() => setConstraints({...constraints, zeroBuffer: !constraints.zeroBuffer})}
            />
            <span>Active Enforced</span>
          </label>
        </div>

        {/* BYOD Isolation */}
        <div className="glass-card">
          <div style={{ display: 'flex', gap: '1rem', marginBottom: '1rem' }}>
            <Shield style={{ color: '#10b981' }} />
            <h3>BYOD Isolation</h3>
          </div>
          <p style={{ color: 'var(--text-dim)', fontSize: '0.9rem', marginBottom: '1.5rem' }}>
            Ensures BYOD students are prioritized for rooms with dedicated power-grid infrastructure.
          </p>
          <label className="switch-container" style={{ display: 'flex', alignItems: 'center', gap: '1rem', cursor: 'pointer' }}>
            <input 
              type="checkbox" 
              checked={constraints.byodIsolation} 
              onChange={() => setConstraints({...constraints, byodIsolation: !constraints.byodIsolation})}
            />
            <span>Active Enforced</span>
          </label>
        </div>

        {/* Building-Batch Affinity */}
        <div className="glass-card">
          <div style={{ display: 'flex', gap: '1rem', marginBottom: '1rem' }}>
            <Home style={{ color: '#3b82f6' }} />
            <h3>Building Affinity</h3>
          </div>
          <p style={{ color: 'var(--text-dim)', fontSize: '0.9rem', marginBottom: '1.5rem' }}>
            Logic for assigning student batches to localized building clusters.
          </p>
          <select 
            className="input-field" 
            value={constraints.buildingAffinity}
            onChange={(e) => setConstraints({...constraints, buildingAffinity: e.target.value})}
            style={{ width: '100%', backgroundColor: 'rgba(255,255,255,0.05)', color: 'white', padding: '0.5rem', borderRadius: '4px', border: '1px solid var(--border)' }}
          >
            <option>Match Batch Year to Building (e.g. 2024 {'->'} B34)</option>
            <option>Departmental Clustering (e.g. CSE {'->'} B32)</option>
            <option>Random Distribution</option>
          </select>
        </div>
      </div>

      <button 
        className="btn-primary" 
        onClick={handleSave}
        style={{ marginTop: '2rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}
      >
        <Save size={18} />
        Update Solver Constraints
      </button>
    </div>
  );
}

