import { Play, Loader2 } from 'lucide-react';

export default function SolverControl() {
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    setLoading(true);
    try {
      const response = await fetch('http://localhost:4000/api/solver/generate-batch', { method: 'POST' });
      const data = await response.json();
      if (data.success) {
        alert(`Success! Generated batch for ${data.stats.students} students.`);
      }
    } catch (err) {
      alert('Network error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="view-container">
      <h2 style={{ marginBottom: '2rem' }}>Solver Orchestration</h2>
      <div className="glass-card" style={{ maxWidth: '600px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <h3>Batch Payload Generation</h3>
            <p style={{ color: 'var(--text-dim)', fontSize: '0.875rem' }}>Full extraction from Supabase to UniTime XML</p>
          </div>
          <button 
            className="btn-primary" 
            onClick={handleGenerate}
            disabled={loading}
            style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
          >
            {loading ? <Loader2 size={18} className="animate-spin" /> : <Play size={18} />}
            {loading ? 'Generating...' : 'Start Job'}
          </button>
        </div>
      </div>

