  const [loading, setLoading] = useState(true);
  const [viewType, setViewType] = useState<'master' | 'student' | 'teacher' | 'room'>('student');
  const [searchId, setSearchId] = useState('');
  const [directory, setDirectory] = useState<any[]>([]);
  const [showDir, setShowDir] = useState(false);

  useEffect(() => {
    if (!searchId && viewType !== 'master') {
      fetchDirectory();
      setShowDir(true);
    } else {
      setShowDir(false);
      fetchSchedule();
    }
  }, [viewType, searchId]);

  const fetchDirectory = () => {
    setLoading(true);
    fetch(`http://localhost:4000/api/directory/${viewType}s`)
      .then(res => res.json())
      .then(data => {
        setDirectory(data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  };

  const fetchSchedule = () => {
    setLoading(true);
    let url = 'http://localhost:4000/api/solver/solution';
    if (viewType !== 'master' && searchId) {
      url += `/${viewType}/${searchId}`;
    }

    fetch(url)
      .then(res => res.json())
      .then(data => {
        setSchedule(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  };

  return (
    <div className="view-container">
