        <div style={{ display: 'flex', gap: '1rem' }}>
          <div style={{ display: 'flex', backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: '8px', padding: '0.25rem' }}>
             <TabButton active={viewType === 'master'} onClick={() => { setViewType('master'); setSearchId(''); }} icon={<BookOpen size={16}/>} label="Master" />
             <TabButton active={viewType === 'student'} onClick={() => { setViewType('student'); setSearchId(''); }} icon={<User size={16}/>} label="Student" />
             <TabButton active={viewType === 'teacher'} onClick={() => { setViewType('teacher'); setSearchId(''); }} icon={<User size={16}/>} label="Teacher" />
             <TabButton active={viewType === 'room'} onClick={() => { setViewType('room'); setSearchId(''); }} icon={<Home size={16}/>} label="Room" />
          </div>
        </div>
      </div>

      <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem' }}>
          <div className="glass-card" style={{ flex: 1, padding: '0.75rem 1rem', display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
            <Search size={18} style={{ color: 'var(--text-dim)' }} />
            <input 
                type="text" 
                placeholder={viewType === 'master' ? "Search all classes..." : `Enter ${viewType} ID (e.g. 12300001, 50001, 25-102)...`}
                value={searchId}
                onChange={(e) => setSearchId(e.target.value)}
                style={{ backgroundColor: 'transparent', border: 'none', color: 'white', outline: 'none', width: '100%' }} 
            />
          </div>
          <button className="btn-secondary" onClick={() => { setSearchId(''); fetchDirectory(); }} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <Filter size={18} /> Clear
          </button>
          <button className="btn-primary" onClick={() => alert('Excel Export Triggered!')} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <FileUp size={18} /> Export
          </button>
      </div>

      {loading ? (
        <div className="glass-card" style={{ padding: '4rem', textAlign: 'center', color: 'var(--text-dim)' }}>
          <Loader2 size={48} className="animate-spin" style={{ margin: '0 auto 1rem' }} />
          <p>Processing request...</p>
        </div>
      ) : showDir ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
          {directory.map((item, idx) => (
            <div 
              key={idx} 
              className="glass-card" 
              onClick={() => setSearchId(item.student_id || item.teacher_id || item.room_id)}
              style={{ cursor: 'pointer', padding: '1.5rem', border: '1px solid var(--border)' }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                <div style={{ 
                  width: '40px', 
                  height: '40px', 
                  borderRadius: '10px', 
                  backgroundColor: 'var(--primary-glow)', 
                  color: 'var(--primary)',
                  display: 'flex',
                  alignItems: 'center',
                 …789 chars truncated…      No records found in this category.
             </div>
          )}
        </div>
