          <div style={{ padding: '1rem' }}>
            {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => {
              const dayClasses = schedule
                .filter(item => (item.time || item.time_slot).startsWith(day))
                .sort((a, b) => {
                  const parseTime = (tStr: string) => {
                    const [time, modifier] = tStr.split(' ');
                    let [hours, minutes] = time.split(':').map(Number);
                    if (modifier === 'PM' && hours !== 12) hours += 12;
                    if (modifier === 'AM' && hours === 12) hours = 0;
                    return hours * 60 + minutes;
                  };
                  const timeA = parseTime((a.time || a.time_slot).split(' ').slice(1, 3).join(' '));
                  const timeB = parseTime((b.time || b.time_slot).split(' ').slice(1, 3).join(' '));
                  return timeA - timeB;
                });

              return (
                <div key={day} style={{ marginBottom: '2rem' }}>
                  <h3 style={{ 
                    padding: '0.5rem 1rem', 
                    backgroundColor: 'rgba(255,255,255,0.05)', 
                    borderRadius: '6px',
                    color: 'var(--primary)',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center'
                  }}>
                    {day === 'Sat' ? `${day} (Reserve/Makeup)` : day}
                    <span style={{ fontSize: '0.8rem', color: 'var(--text-dim)' }}>{dayClasses.length} Sessions</span>
                  </h3>

                  {dayClasses.length > 0 ? (
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', marginTop: '0.5rem' }}>
                      <thead>
                        <tr style={{ color: 'var(--text-dim)', fontSize: '0.8rem', borderBottom: '1px solid var(--border)' }}>
                          <th style={{ padding: '0.75rem 1rem' }}>Time</th>
                          <th style={{ padding: '0.75rem 1rem' }}>Course</th>
                          <th style={{ padding: '0.75rem 1rem' }}>Room</th>
                          <th style={{ padding: '0.75rem 1rem' }}>
                            {viewType === 'teacher' ? 'Section' : 'Instructor'}
                          </th>
                        </tr>
                      </thead>
                      <tbody>
                        {dayClasses.map((item, idx) => (
                          <tr key={idx} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                            <td style={{ padding: '1rem', fontWeight: 600, color: 'var(--accent)' }}>
                              {(item.time || item.time_slot).split(' ').slice(1).join(' ')}
                            </td>
                            <td style={{ padding: '1rem' }}>
                              <div style={{ fontWeight: 600 }}>{item.code || item.course_code}</div>
                              <div style={{ fontSize: '0.75rem', color: 'var(--text-dim)' }}>{item.section || item.section_name}</div>
                            </td>
                            <td style={{ padding: '1rem' }}>{item.room || item.room_id}</td>
                            <td style={{ padding: '1rem', color: 'var(--text-dim)' }}>
                              {viewType === 'teacher'
                                ? (item.section || item.section_name)
                                : item.instructor}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  ) : (
                    <div style={{ padding: '1.5rem', textAlign: 'center', color: 'var(--text-dim)', fontSize: '0.9rem', border: '1px dashed var(--border)', borderRadius: '8px', marginTop: '0.5rem' }}>
                      No scheduled sessions for {day}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

function TabButton({ active, onClick, icon, label }: any) {
    return (
        <button 
            onClick={onClick}
            style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                padding: '0.5rem 1rem',
                borderRadius: '6px',
                border: 'none',
                cursor: 'pointer',
                fontSize: '0.875rem',
                backgroundColor: active ? 'var(--primary)' : 'transparent',
                color: active ? 'white' : 'var(--text-dim)',
                transition: 'all 0.2s'
            }}
        >
            {icon}
            {label}
        </button>
    )
}

:root {
  --bg: #0f172a;
  --glass: rgba(30, 41, 59, 0.7);
  --glass-border: rgba(255, 255, 255, 0.1);
  --primary: #7c3aed;
  --primary-glow: rgba(124, 58, 237, 0.3);
  --accent: #10b981;
  --accent-glow: rgba(16, 185, 129, 0.2);
  --text: #f8fafc;
  --text-dim: #94a3b8;
  --border: rgba(255, 255, 255, 0.05);
  --danger: #ef4444;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
}

body {
  background-color: var(--bg);
  background-image: 
    radial-gradient(circle at 0% 0%, rgba(124, 58, 237, 0.15) 0%, transparent 50%),
    radial-gradient(circle at 100% 100%, rgba(16, 185, 129, 0.1) 0%, transparent 50%);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
}

.app-container {
  display: flex;
  min-height: 100vh;
}

/* Sidebar Styling */
.sidebar {
  width: 280px;
  background: var(--glass);
  backdrop-filter: blur(12px);
  border-right: 1px solid var(--glass-border);
  display: flex;
  flex-direction: column;
  padding: 2rem 1.5rem;
  position: fixed;
  height: 100vh;
  z-index: 100;
}

.logo {
  font-size: 1.5rem;
  font-weight: 800;
  background: linear-gradient(to right, #7c3aed, #10b981);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin-bottom: 3rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.nav-group {
  margin-bottom: 2.5rem;
}

.nav-label {
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--text-dim);
  margin-bottom: 1rem;
  padding-left: 0.5rem;
}

.nav-item {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 0.75rem 1rem;
  color: var(--text-dim);
  text-decoration: none;
  border-radius: 12px;
  margin-bottom: 0.5rem;
  transition: all 0.3s ease;
  cursor: pointer;
}

.nav-item:hover {
  background: rgba(255, 255, 255, 0.05);
  color: var(--text);
}

.nav-item.active {
  background: var(--primary);
  color: white;
  box-shadow: 0 4px 15px var(--primary-glow);
}

/* Main Content Area */
.main-content {
  flex: 1;
  margin-left: 280px;
  padding: 2.5rem 3rem;
  animation: fadeIn 0.5s ease;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Glass Components */
.glass-card {
  background: var(--glass);
  backdrop-filter: blur(12px);
  border: 1px solid var(--glass-border);
  border-radius: 20px;
  padding: 2rem;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
  transition: transform 0.3s ease, border-color 0.3s ease;
}

.glass-card:hover {
  border-color: rgba(255, 255, 255, 0.2);
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2.5rem;
}

/* Buttons */
.btn-primary {
  background: var(--primary);
  color: white;
  border: none;
  padding: 0.75rem 1.5rem;
  border-radius: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 5px 15px var(--primary-glow);
  background: #8b5cf6;
}

.btn-secondary {
  background: rgba(255, 255, 255, 0.05);
  color: var(--text);
  border: 1px solid var(--glass-border);
  padding: 0.75rem 1.5rem;
  border-radius: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.btn-secondary:hover {
  background: rgba(255, 255, 255, 0.1);
}

/* Workflow Stepper */
.stepper {
  display: flex;
  justify-content: space-between;
  margin-bottom: 3rem;
  position: relative;
}

.stepper::before {
  content: '';
  position: absolute;
  top: 20px;
  left: 50px;
  right: 50px;
  height: 2px;
  background: var(--border);
  z-index: 0;
}

.step {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.75rem;
  z-index: 1;
  position: relative;
  width: 100px;
}

.step-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--bg);
  border: 2px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  transition: all 0.3s ease;
}

.step.active .step-circle {
  border-color: var(--primary);
  background: var(--primary);
  box-shadow: 0 0 15px var(--primary-glow);
}

.step.completed .step-circle {
  border-color: var(--accent);
  background: var(--accent);
}

.step-label {
  font-size: 0.8rem;
  color: var(--text-dim);
  font-weight: 600;
}

.step.active .step-label {
  color: var(--text);
}

/* Inputs */
.input-field {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  padding: 1rem;
  color: var(--text);
  width: 100%;
  outline: none;
  transition: border-color 0.3s ease;
}

.input-field:focus {
  border-color: var(--primary);
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: var(--bg);
}

::-webkit-scrollbar-thumb {
  background: var(--glass-border);
  border-radius: 10px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.2);
}

